import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    try:
        user_input = input("Enter a command: ").strip()

        if not user_input:
            print("Error: No command provided")
            return

        # Validate command - only allow alphanumeric, common command characters
        # and prevent shell metacharacters that could enable injection
        dangerous_chars = ['&', '|', ';', '`', '$', '(', ')', '<', '>', '\n', '\r']
        if any(char in user_input for char in dangerous_chars):
            print("Error: Command contains invalid characters")
            return

        # Use shlex to safely parse the command into arguments
        args = shlex.split(user_input)

        # Whitelist of allowed commands for additional security
        allowed_commands = {
            'echo', 'ls', 'pwd', 'date', 'whoami', 'cat', 'grep', 'find',
            'wc', 'sort', 'uniq', 'head', 'tail', 'mkdir', 'rm', 'cp', 'mv'
        }

        if args[0] not in allowed_commands:
            print(f"Error: Command '{args[0]}' is not allowed")
            return

        # Execute the command with shell=False for security
        result = subprocess.run(args, capture_output=True, text=True, timeout=10)

        if result.stdout:
            print(result.stdout)
        if result.stderr:
            print("Error:", result.stderr)

        if result.returncode != 0:
            print(f"Command exited with code {result.returncode}")

    except subprocess.TimeoutExpired:
        print("Error: Command execution timed out")
    except FileNotFoundError:
        print("Error: Command not found")
    except Exception as e:
        print(f"Error: {str(e)}")

if __name__ == "__main__":
